// Turn the comma-separated watchlist into one item per ticker.
// Capped at 6 tickers: the whole briefing then costs at most
// 6 tickers x 3 calls + 1 trending = 19 AlphaAI calls -> fits the Free tier
// (20 req/min, 100 req/day) in a single burst. Raise the cap on Basic/Pro.
const cfg = $input.first().json;
const tickers = String(cfg.watchlist || '')
  .split(',')
  .map(t => t.trim().toUpperCase())
  .filter(Boolean);

const MAX_FREE = 6;
const capped = tickers.slice(0, MAX_FREE);

return capped.map(ticker => ({
  json: {
    ticker,
    min_relevance: cfg.min_relevance ?? 6,
    urgent_min_score: cfg.urgent_min_score ?? 8,
  },
}));

// Join the four AlphaAI branches into one structured briefing object.
// Items are read from the named nodes (the Merge before this node is a
// synchronization barrier), zipped by ticker order — n8n preserves item order.

function trunc(s, n) {
  s = (s == null ? '' : String(s));
  return s.length > n ? s.slice(0, n - 1) + '…' : s;
}
function slugify(text) {
  return (text || '').toLowerCase()
    .replace(/[^\w\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .trim();
}
function dateForUrl(iso) {
  const d = new Date(iso);
  if (isNaN(d.getTime())) { return ''; }
  const m = String(d.getUTCMonth() + 1).padStart(2, '0');
  const day = String(d.getUTCDate()).padStart(2, '0');
  return `${m}-${day}`;
}
function articleUrl(org) {
  const base = `https://alphai.io/news/article/${dateForUrl(org.time_published)}/${org.uid}/${slugify(org.title)}`;
  return `${base}?utm_source=n8n&utm_medium=email&utm_campaign=morning_briefing`;
}
function usdM(v) {
  const n = Number(v);
  if (!v || isNaN(n) || n === 0) { return null; }
  const abs = Math.abs(n);
  if (abs >= 1e9) { return `$${(n / 1e9).toFixed(1)}B`; }
  if (abs >= 1e6) { return `$${(n / 1e6).toFixed(1)}M`; }
  return `$${Math.round(n / 1e3)}K`;
}
function pickArticles(resp, minScore, cap) {
  let rows = [];
  const j = resp || {};
  if (Array.isArray(j)) { rows = j; }
  else if (Array.isArray(j.results)) { rows = j.results; }
  const out = [];
  for (const a of rows) {
    const org = (a && a.original) || {};
    const enr = (a && a.enrichment) || {};
    if (!org.uid || (enr.relevance_score || 0) < minScore) { continue; }
    const ta = ((enr.ai_trading_insights || {}).ticker_analysis || [])[0] || {};
    const ia = ta.impact_analysis || {};
    out.push({
      title: trunc(org.title, 160),
      url: articleUrl(org),
      published: org.time_published,
      score: enr.relevance_score || 0,
      category: enr.category || 'other',
      tickers: enr.tickers || [],
      sentiment: ia.sentiment || 'neutral',
      summary: trunc(org.summary || ia.summary || '', 220),
    });
    if (out.length >= cap) { break; }
  }
  return out;
}

const tickerItems = $('Split Watchlist by Ticker').all().map(i => i.json);
const newsItems = $('Fetch Ticker News').all();
const sentItems = $('Fetch 7-Day Sentiment').all();
const insItems = $('Fetch 30-Day Insider Activity').all();
const trendItems = $('Fetch Trending Market News').all();

const urgentMin = (tickerItems[0] || {}).urgent_min_score || 8;
const minRel = (tickerItems[0] || {}).min_relevance || 6;
const DAY_MS = 24 * 60 * 60 * 1000;
const now = Date.now();

const watchlist = [];
const redFlags = [];

for (let i = 0; i < tickerItems.length; i++) {
  const ticker = tickerItems[i].ticker;
  const newsJ = (newsItems[i] || {}).json || {};
  const sentJ = (sentItems[i] || {}).json || {};
  const insJ = (insItems[i] || {}).json || {};

  const articles = newsJ.error ? [] : pickArticles(newsJ, minRel, 5);

  // Deterministic red flags — the AI narrates them, code decides them.
  for (const a of articles) {
    const fresh = a.published && (now - new Date(a.published).getTime()) < DAY_MS;
    if (!fresh) { continue; }
    if (a.sentiment === 'negative' && a.score >= urgentMin) {
      redFlags.push({ ticker, reason: `Bearish high-relevance news (score ${a.score}): ${a.title}`, url: a.url });
    } else if (a.category === 'insider' && a.score >= 7) {
      redFlags.push({ ticker, reason: `Notable insider filing (score ${a.score}): ${a.title}`, url: a.url });
    }
  }

  const sentiment = sentJ.error ? null : {
    days: sentJ.days ?? 7,
    total: sentJ.total ?? 0,
    bullish: sentJ.bullish ?? 0,
    neutral: sentJ.neutral ?? 0,
    bearish: sentJ.bearish ?? 0,
  };

  let insider = null;
  if (!insJ.error && (insJ.total_transactions ?? 0) > 0) {
    const top = (insJ.top_insiders || [])[0] || {};
    insider = {
      days: insJ.days ?? 30,
      buys: insJ.buy_count ?? 0,
      sells: insJ.sell_count ?? 0,
      bought: usdM(insJ.buy_value_usd),
      sold: usdM(insJ.sell_value_usd),
      pct_10b5_1: insJ.pct_10b5_1 ?? 0,
      top_insider: top.name ? `${top.name}${top.title ? ' (' + top.title + ')' : ''}, ${top.transaction_count} tx, net ${usdM(top.net_value) || 'n/a'}` : null,
    };
  }

  watchlist.push({ ticker, sentiment, insider, articles });
}

const market = pickArticles(((trendItems[0] || {}).json) || {}, 7, 5)
  .filter(a => !watchlist.some(w => w.articles.some(x => x.url === a.url)));

const quiet = watchlist
  .filter(w => w.articles.length === 0 && !w.insider)
  .map(w => w.ticker);

const briefing = {
  date: new Date(now).toISOString().slice(0, 10),
  watchlist: watchlist.filter(w => !quiet.includes(w.ticker)),
  quiet_tickers: quiet,
  market,
  red_flags: redFlags,
};

return [{
  json: {
    briefing,
    llm_input: JSON.stringify(briefing),
    has_red_flags: redFlags.length > 0,
    red_flags: redFlags,
  },
}];

// Render the AI brief: Markdown -> email-safe HTML, plus the urgent
// Discord payload for the red-flag branch.
const ai = $input.first().json;
const data = $('Assemble Briefing Data').first().json;
const md = ai.text || ai.output || '';

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}
function inline(s) {
  return s
    .replace(/\[([^\]]+)\]\((https?:[^\s)]+)\)/g, '<a href="$2" style="color:#0a5c46;">$1</a>')
    .replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>')
    .replace(/\*([^*]+)\*/g, '<em>$1</em>')
    .replace(/`([^`]+)`/g, '<code>$1</code>');
}

const lines = esc(md).split('\n');
const parts = [];
let inList = false;
for (const raw of lines) {
  const line = raw.trim();
  const isBullet = /^[-*] /.test(line);
  if (inList && !isBullet) { parts.push('</ul>'); inList = false; }
  if (!line) { continue; }
  if (line.startsWith('### ')) { parts.push(`<h3 style="margin:18px 0 6px;font-size:15px;">${inline(line.slice(4))}</h3>`); }
  else if (line.startsWith('## ')) { parts.push(`<h2 style="margin:22px 0 8px;font-size:17px;border-bottom:1px solid #e5e5e5;padding-bottom:4px;">${inline(line.slice(3))}</h2>`); }
  else if (line.startsWith('# ')) { parts.push(`<h1 style="margin:0 0 10px;font-size:20px;">${inline(line.slice(2))}</h1>`); }
  else if (isBullet) {
    if (!inList) { parts.push('<ul style="margin:6px 0;padding-left:20px;">'); inList = true; }
    parts.push(`<li style="margin:4px 0;">${inline(line.slice(2))}</li>`);
  }
  else { parts.push(`<p style="margin:8px 0;">${inline(line)}</p>`); }
}
if (inList) { parts.push('</ul>'); }

const flagBanner = data.has_red_flags
  ? `<div style="background:#fdecea;border:1px solid #e57373;border-radius:6px;padding:10px 14px;margin:0 0 14px;"><strong>🚩 ${data.red_flags.length} red flag${data.red_flags.length > 1 ? 's' : ''} before the open</strong></div>`
  : '';

const email_html = `<!doctype html><html><body style="margin:0;padding:0;background:#f6f6f4;">
<div style="max-width:640px;margin:0 auto;padding:24px;background:#ffffff;font-family:Arial,Helvetica,sans-serif;font-size:14px;line-height:1.55;color:#1a1a1a;">
${flagBanner}
${parts.join('\n')}
<hr style="border:none;border-top:1px solid #e5e5e5;margin:24px 0 12px;">
<p style="font-size:12px;color:#888;">Enriched news, sentiment &amp; SEC Form 4 data by <a href="https://alphai.io?utm_source=n8n&amp;utm_medium=email&amp;utm_campaign=morning_briefing" style="color:#0a5c46;">AlphaAI</a> · brief written by your own AI model · assembled with n8n</p>
</div></body></html>`;

const subject = data.has_red_flags
  ? `🚩 Morning Market Briefing ${data.briefing.date} — ${data.red_flags.length} red flag${data.red_flags.length > 1 ? 's' : ''}`
  : `☀️ Morning Market Briefing ${data.briefing.date} — all clear`;

const urgent_payload = {
  content: `🚩 **Pre-open red flags — ${data.briefing.date}**`,
  embeds: (data.red_flags || []).slice(0, 10).map(f => ({
    title: `${f.ticker} — check before the open`,
    description: f.reason,
    url: f.url,
    color: 15158332,
  })),
};

return [{ json: { subject, email_html, has_red_flags: data.has_red_flags, urgent_payload } }];
